/* getLoginUserInfo */ SELECT EMAIL , PWD , USERNAME , PHONE , SMS_YN , EMAIL_YN , INPUT_DT , INPUT_ID , UPDATE_DT , UPDATE_ID FROM USER_INFO
AND EMAIL = #{email}
USERNAME = #{username} AND ( EMAIL = #{email_phone} OR PHONE = #{email_phone} )
LIMIT 1

/* getUserInfo */ SELECT EMAIL , PWD , USERNAME , PHONE , SMS_YN , EMAIL_YN , INPUT_DT , INPUT_ID , UPDATE_DT , UPDATE_ID FROM USER_INFO
AND EMAIL = #{email}
USERNAME = #{username} AND ( EMAIL = #{email_phone} OR PHONE = #{email_phone} )
LIMIT 1

/* 이메일 중복체크 getEmailDupChk */
SELECT  COUNT(1) AS CNT
FROM    USER_INFO
WHERE   EMAIL  = #{EMAIL}

