INSERT INTO PHONE_AUTH_INFO
(
	USER_NAME
  , AUTH_NUM
  , GROUP_ID
  , MSG_ID
  , ACCOUNT_ID
  , TO_PHONE
  , STAT_CODE
  , STAT_MSG
  , COUNTRY
  , INPUT_DT
  , INPUT_ID
)
VALUES
(
	#{USER_NAME}
  , #{AUTH_NUM}
  , #{GROUP_ID}
  , #{MSG_ID}
  , #{ACCOUNT_ID}
  , #{TO_PHONE}
  , #{STAT_CODE}
  , #{STAT_MSG}
  , #{COUNTRY}
  , NOW()
  , 'SYSTEM'
)

	SELECT LAST_INSERT_ID()

