mapper.insert:
/* jaram.user.mapper.UserMapper.insertEmailCertNum [인증코드 이메일 저장] */
INSERT
INTO    EMAIL_CERT_INFO
(
    SESSION_ID
  , EMAIL
  , CERT_NUM
  , PAGE
  , INPUT_DT
  , INPUT_ID
)
VALUES
(
   #{SESSION_ID}
 , #{EMAIL}
 , #{CERT_NUM}
 , #{PAGE}
 , NOW()
 , 'SYSTEM'
)

mapper.select:
/* jaram.user.mapper.UserMapper.selectEmailCertNum [인증코드 조회] */
SELECT  SESSION_ID
	  , EMAIL
	  , SEQ
FROM    EMAIL_CERT_INFO
WHERE   SEQ        = (SELECT MAX(SEQ) FROM EMAIL_CERT_INFO WHERE SESSION_ID = #{SESSION_ID} AND EMAIL = #{EMAIL})
AND     SESSION_ID = #{SESSION_ID}
AND     EMAIL      = #{EMAIL}
AND     CERT_NUM   = #{CERT_NUM}

mapper.update:
/* jaram.user.mapper.UserMapper.updateEmailCertYn [인증코드 인증 완료 여부 변경] */
UPDATE  EMAIL_CERT_INFO
SET     CERT_YN = 'Y'
WHERE   SEQ     = #{SEQ}

