SELECT  CERT_YN
FROM    EMAIL_CERT_INFO
WHERE   SEQ        = (SELECT MAX(SEQ) FROM EMAIL_CERT_INFO WHERE EMAIL = #{email})
AND     EMAIL      = #{email}

